function normalizedData = normalizePositiveIndicators(data,
positiveCols)
% 初始化输出矩阵
normalizedData = data;
% 遍历所有正向指标列
for col = positiveCols
% 提取当前列数据
currentCol = data(:, col);
% 计算最小值和范围
minVal = min(currentCol);
maxVal = max(currentCol);

